import{_ as a,c as o,o as i,ah as s}from"./chunks/framework.C-x9UAyH.js";const m=JSON.parse('{"title":"Conceptos básicos de Springboot","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"springboot/conceptos.md","filePath":"springboot/conceptos.md","lastUpdated":1745877900000}'),r={name:"springboot/conceptos.md"};function t(c,e,n,l,d,p){return i(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="conceptos-basicos-de-springboot" tabindex="-1">Conceptos básicos de Springboot <a class="header-anchor" href="#conceptos-basicos-de-springboot" aria-label="Permalink to &quot;Conceptos básicos de Springboot&quot;">​</a></h1><h2 id="🌱-spring-boot" tabindex="-1">🌱 Spring Boot <a class="header-anchor" href="#🌱-spring-boot" aria-label="Permalink to &quot;🌱 Spring Boot&quot;">​</a></h2><p>Es un framework de Java que ayuda a crear aplicaciones web rápido y fácil.</p><ul><li>Está basado en microservicios.</li><li>Ya viene con muchas cosas configuradas (como un servidor web, base de datos, etc.).</li><li>No se necesita instalar servidores aparte como antes (por ejemplo, Tomcat viene incluido).</li><li>Se enfoca en que cada aplicación sea autosustentable: se puede ejecutar sola, sin depender de cosas externas.</li></ul><p>Ejemplo: hacer una app con Spring Boot, se empaqueta y se puede correr sola con java -jar.</p><h2 id="🧱-archivo-war" tabindex="-1">🧱 Archivo .war <a class="header-anchor" href="#🧱-archivo-war" aria-label="Permalink to &quot;🧱 Archivo .war&quot;">​</a></h2><ul><li>Es un archivo Java Web clásico (Web Application Archive).</li><li>Se usaba antes para desplegar aplicaciones dentro de un servidor como Tomcat o JBoss.</li><li>Hoy en día, con Spring Boot, ya se no necesita un .war. Se usa .jar (Java Archive), que se ejecuta directamente.</li></ul><h2 id="🧩-microservicios" tabindex="-1">🧩 Microservicios <a class="header-anchor" href="#🧩-microservicios" aria-label="Permalink to &quot;🧩 Microservicios&quot;">​</a></h2><p>Son pequeñas aplicaciones independientes, cada una encargada de una sola cosa dentro de un sistema más grande.</p><p>Por ejemplo:</p><ul><li>Un microservicio maneja los usuarios.</li><li>Otro microservicio maneja los pagos.</li><li>Otro maneja los correos.</li></ul><p>Cada uno tiene:</p><ul><li>Su propio código.</li><li>Su propia base de datos.</li><li>Su propia infraestructura.</li></ul><h2 id="🔁-microservicios-vs-monolito" tabindex="-1">🔁 Microservicios vs Monolito <a class="header-anchor" href="#🔁-microservicios-vs-monolito" aria-label="Permalink to &quot;🔁 Microservicios vs Monolito&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Monolito</th><th>Microservcio</th></tr></thead><tbody><tr><td>Todo está en una sola aplicación gigante</td><td>Todo está separado</td></tr><tr><td>Si cambias algo, puedes romper otra parte (por eso hacemos pruebas de no impacto)</td><td>Cada parte puede crecer o escalar sola</td></tr><tr><td>Si necesitas más potencia, tienes que escalar todo el sistema, aunque solo lo necesite una parte</td><td>Si algo falla, no afecta todo lo demás</td></tr><tr><td></td><td>Facilita el trabajo en equipo y el mantenimiento</td></tr></tbody></table><h2 id="🚀-¿que-es-escalar" tabindex="-1">🚀 ¿Qué es escalar? <a class="header-anchor" href="#🚀-¿que-es-escalar" aria-label="Permalink to &quot;🚀 ¿Qué es escalar?&quot;">​</a></h2><p>Es darle más recursos (como más CPU, RAM, instancias) a una aplicación para que pueda atender a más usuarios.</p><ul><li>En un monolito: escalo toda la aplicación.</li><li>En microservicios: escalo solo el microservicio que lo necesita.</li></ul><h2 id="🔗-¿como-se-comunican-los-microservicios" tabindex="-1">🔗 ¿Cómo se comunican los microservicios? <a class="header-anchor" href="#🔗-¿como-se-comunican-los-microservicios" aria-label="Permalink to &quot;🔗 ¿Cómo se comunican los microservicios?&quot;">​</a></h2><ul><li>Usan API REST con JSON como formato de intercambio de datos.</li><li>Esto permite que microservicios escritos en diferentes lenguajes (Java, .NET, Python) puedan hablar entre sí.</li></ul><h2 id="✅-ventajas-de-los-microservicios" tabindex="-1">✅ Ventajas de los Microservicios <a class="header-anchor" href="#✅-ventajas-de-los-microservicios" aria-label="Permalink to &quot;✅ Ventajas de los Microservicios&quot;">​</a></h2><p>🚀 Escalabilidad: cada parte puede crecer por separado.</p><p>🧰 Fácil mantenimiento: cambiar algo no afecta todo.</p><p>🔄 Despliegue independiente: puedes actualizar un solo servicio.</p><p>🔗 Desacoplamiento: cada uno funciona por su cuenta.</p><h2 id="⚠️-desventajas" tabindex="-1">⚠️ Desventajas <a class="header-anchor" href="#⚠️-desventajas" aria-label="Permalink to &quot;⚠️ Desventajas&quot;">​</a></h2><p>📚 Más complejo: tienes que manejar muchos servicios.</p><p>📡 Overhead de comunicación: todo pasa por red.</p><p>🔐 Manejo de transacciones es más difícil (porque cada servicio tiene su base de datos).</p>',29)])])}const h=a(r,[["render",t]]);export{m as __pageData,h as default};
